https://godbolt.org/z/r1xxh9Yvs
icmp with variables are also not optimized.
```
#include <stdint.h>

int firewall3(const uint8_t *restrict data, int a) {
    const uint32_t src = *((const uint32_t *)data);

    if ((src & 0xFFFF0000) == a) return 1;
    if ((src & 0xFFFFFF00) == a) return 1;

    return 0;
}

int firewall4(const uint8_t *restrict data, int a) {
    const uint32_t src = *((const uint32_t *)data);

    if ((src & 0xFFFFFF00) == a) return 1;
    if ((src & 0xFFFF0000) == a) return 1;

    return 0;
}
```

> https://godbolt.org/z/r1xxh9Yvs icmp with variables are also not optimized.
> 
